from __future__ import annotations
import json, pathlib, re, datetime, html
ROOT=pathlib.Path.cwd(); PUBLIC=ROOT/'public'; ASSETS=PUBLIC/'assets'
CANONICAL='goalos.html'; ALIASES=['mission-autopilot.html','tell-goalos.html','universal-mission-autopilot.html']
BOUNDARY='No user data. No user funds. No wallet. No transaction. No network call. No production authority. Human review required.'
TOKEN='$AGIALPHA public contract address only. Not available from us. No sale. No custody. No wallet support. No investment, trading, legal, tax, exchange, bridge, liquidity, or regulatory advice.'
VERSION='v22'
def esc(s): return html.escape(str(s), quote=True)
def write(p, s):
    p=pathlib.Path(p); p.parent.mkdir(parents=True, exist_ok=True); p.write_text(s, encoding='utf-8')
def read(p):
    try: return pathlib.Path(p).read_text(encoding='utf-8')
    except Exception: return ''
def title_from_html(path):
    txt=read(path); m=re.search(r'<title[^>]*>(.*?)</title>', txt, re.I|re.S)
    if m: return re.sub(r'\s+',' ',m.group(1)).strip()
    h=re.search(r'<h1[^>]*>(.*?)</h1>', txt, re.I|re.S)
    if h: return re.sub(r'<[^>]+>',' ',h.group(1)).strip()
    return path.stem.replace('-',' ').title()
def desc_from_html(path):
    txt=read(path)
    m=re.search(r'<meta[^>]+name=["\']description["\'][^>]+content=["\'](.*?)["\']', txt, re.I|re.S)
    if m: return re.sub(r'\s+',' ',m.group(1)).strip()
    p=re.search(r'<p[^>]*>(.*?)</p>', txt, re.I|re.S)
    if p: return re.sub(r'\s+',' ',re.sub(r'<[^>]+>',' ',p.group(1))).strip()[:220]
    return 'Open this GoalOS public route.'
def classify(name, title, desc):
    s=(name+' '+title+' '+desc).lower()
    if name=='404.html': return 'System'
    if any(k in s for k in ['start','pathfinder','site-map','all pages','search','docs','website operating','site health']): return 'Navigation & Docs'
    if any(k in s for k in ['mainnet','contract atlas','proof rail','ethereum','contract academy','token']): return 'Mainnet & Token'
    if any(k in s for k in ['rsi','loop','move-37','omni','bottleneck','flight recorder']): return 'Loop to RSI'
    if any(k in s for k in ['proof run','evidence','docket','reviewer','validator','ledger','falsification','gauntlet']): return 'Evidence & Review'
    if any(k in s for k in ['trust','privacy','data','boundary','security','legal','no-data','funds']): return 'Trust & Boundary'
    if any(k in s for k in ['mission','objective','command','autopilot','goalos.html','ask-goalos','concierge']): return 'Mission Autopilot'
    if any(k in s for k in ['capability','value','settlement','economy','work','agent','node','jobs']): return 'Capability & Economy'
    return 'Additional'
def simple_page(title, desc, category='GoalOS'):
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{esc(title)}</title><meta name="description" content="{esc(desc)}"><link rel="stylesheet" href="assets/goalos-universal-interface-v22.css"></head><body><div class="wrap">{page_nav('')}<section class="hero"><div><div class="eyebrow">{esc(category)}</div><h1>{esc(title)}</h1><p>{esc(desc)}</p><div><a class="btn primary" href="goalos.html">Tell GoalOS what you want</a> <a class="btn secondary" href="site-map.html">Open all pages</a></div><div class="boundary"><b>Public-alpha boundary.</b> {BOUNDARY}</div></div></section><footer class="footer"><p>{TOKEN}</p></footer></div><a class="v22-float" href="goalos.html">Tell GoalOS</a></body></html>'''
def inventory():
    PUBLIC.mkdir(exist_ok=True); ASSETS.mkdir(parents=True, exist_ok=True)
    routes=[]
    for p in sorted(PUBLIC.glob('*.html')):
        title=title_from_html(p); desc=desc_from_html(p); name=p.name
        cat='Mission Autopilot' if name in [CANONICAL]+ALIASES else classify(name,title,desc)
        routes.append({'title':title,'url':name,'category':cat,'description':desc})
    existing={r['url'] for r in routes}
    essentials=[('index.html','GoalOS Command Center','The institutional front door.'),('start-here.html','Start Here','Start in 60 seconds.'),('pathfinder.html','Pathfinder','Choose a route by role.'),('site-map.html','All Pages','Every public route.'),('search.html','Search','Browser-local route search.'),('site-health.html','Site Health','Route and boundary status.'),('demo-ecosystem-registry.html','Demo Registry','Inputs, outputs, proof gates, and states.'),('proof-run-001-docket.html','Proof Run 001','Evidence Docket and reviewer path.'),('mainnet-contract-atlas.html','Mainnet Contract Atlas','48 GoalOS-created Ethereum Mainnet contracts.'),('mainnet-proof-rail.html','Mainnet Proof Rail','Public proof rail explained.'),('contract-academy.html','Contract Academy','Learn the GoalOS contract system.'),('trust-boundary.html','Trust Boundary','No data, no funds, no wallet, no transaction.'),('token-boundary.html','Token Boundary','$AGIALPHA public contract identification only.')]
    for name,title,desc in essentials:
        if name not in existing:
            write(PUBLIC/name, simple_page(title, desc, category=classify(name,title,desc)))
            routes.append({'title':title,'url':name,'category':classify(name,title,desc),'description':desc})
    return sorted(routes, key=lambda r:(r['category'], r['title']))
