def patch_all_pages():
    protected=[CANONICAL,'index.html','site-map.html','search.html','demo-ecosystem-registry.html','site-health.html','trust-boundary.html','token-boundary.html']+ALIASES
    for p in PUBLIC.glob('*.html'):
        if p.name in protected: continue
        txt=read(p)
        if not txt.strip(): continue
        if 'goalos-universal-interface-v22.css' not in txt:
            txt=re.sub(r'</head>', '<link rel="stylesheet" href="assets/goalos-universal-interface-v22.css"><link rel="stylesheet" href="assets/goalos-universal-interface-float-v22.css"></head>', txt, flags=re.I)
        if 'v22-float' not in txt:
            txt=re.sub(r'</body>', '<a class="v22-float" href="goalos.html">Tell GoalOS</a></body>', txt, flags=re.I)
        write(p,txt)
